# ── EMBEDDED GAME HTML ───────────────────────────────────────────────────────
SEQUENCE_TAP_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>MindBoost — Sequence Tap</title>\n<link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@700;900&family=Rajdhani:wght@400;600&display=swap" rel="stylesheet">\n<style>\n  :root{--purple:#b537f2;--cyan:#00f5ff;--pink:#ff2d78;--green:#00e88a;--bg:#050510;--card:rgba(15,10,40,0.85);--border:rgba(181,55,242,0.3);--text:#e8e0ff;--muted:#7a6f9a;}\n  *{margin:0;padding:0;box-sizing:border-box;}\n  body{font-family:\'Rajdhani\',sans-serif;background:var(--bg);color:var(--text);min-height:100vh;}\n  body::before{content:\'\';position:fixed;inset:0;pointer-events:none;background-image:linear-gradient(rgba(181,55,242,0.05) 1px,transparent 1px),linear-gradient(90deg,rgba(181,55,242,0.05) 1px,transparent 1px);background-size:40px 40px;}\n  nav{display:flex;align-items:center;justify-content:space-between;padding:14px 28px;border-bottom:1px solid var(--border);background:rgba(5,5,16,0.95);backdrop-filter:blur(16px);}\n  .nav-logo{font-family:\'Orbitron\',monospace;font-size:16px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;}\n  .nav-btn{padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--text);font-family:\'Rajdhani\',sans-serif;font-size:13px;font-weight:600;border-radius:6px;cursor:pointer;transition:all 0.2s;text-decoration:none;display:inline-block;letter-spacing:1px;}\n  .nav-btn:hover{background:rgba(181,55,242,0.2);border-color:var(--purple);color:var(--cyan);}\n\n  .container{max-width:620px;margin:0 auto;padding:28px 20px;position:relative;z-index:1;}\n\n  .hud{display:flex;justify-content:space-between;align-items:center;background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:12px;padding:16px 24px;margin-bottom:20px;}\n  .hud-item{text-align:center;}\n  .hud-label{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);}\n  .hud-value{font-family:\'Orbitron\',monospace;font-size:26px;font-weight:900;color:var(--cyan);}\n\n  .status-bar{text-align:center;margin-bottom:16px;min-height:44px;display:flex;align-items:center;justify-content:center;}\n  .status-text{font-family:\'Orbitron\',monospace;font-size:14px;letter-spacing:2px;padding:10px 24px;border-radius:8px;transition:all 0.3s;}\n  .status-watch{color:var(--cyan);background:rgba(0,245,255,0.08);border:1px solid rgba(0,245,255,0.3);}\n  .status-go{color:var(--green);background:rgba(0,232,138,0.08);border:1px solid rgba(0,232,138,0.3);}\n  .status-wrong{color:var(--pink);background:rgba(255,45,120,0.08);border:1px solid rgba(255,45,120,0.3);animation:shake 0.3s ease;}\n  .status-correct{color:var(--green);background:rgba(0,232,138,0.08);border:1px solid rgba(0,232,138,0.3);}\n  @keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}\n\n  .board-wrap{background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:16px;padding:24px;}\n  .grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;max-width:420px;margin:0 auto;}\n\n  .tile{aspect-ratio:1;border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:32px;cursor:pointer;border:2px solid rgba(255,255,255,0.1);transition:all 0.15s;user-select:none;position:relative;overflow:hidden;}\n  .tile::after{content:\'\';position:absolute;inset:0;border-radius:12px;opacity:0;transition:opacity 0.15s;background:rgba(255,255,255,0.25);}\n  .tile:hover:not(.locked){transform:scale(1.04);border-color:rgba(181,55,242,0.5);}\n  .tile.locked{cursor:default;pointer-events:none;}\n\n  .tile-0{background:linear-gradient(135deg,#1a0533,#2d0a52);}\n  .tile-1{background:linear-gradient(135deg,#001a33,#002952);}\n  .tile-2{background:linear-gradient(135deg,#001a1a,#003333);}\n  .tile-3{background:linear-gradient(135deg,#1a1a00,#2e2e00);}\n  .tile-4{background:linear-gradient(135deg,#1a0020,#330040);}\n  .tile-5{background:linear-gradient(135deg,#001a0d,#003319);}\n  .tile-6{background:linear-gradient(135deg,#1a0a00,#331500);}\n  .tile-7{background:linear-gradient(135deg,#0a001a,#160033);}\n  .tile-8{background:linear-gradient(135deg,#001a1a,#00302e);}\n\n  .tile.flash-active{transform:scale(1.1)!important;border-color:rgba(255,255,255,0.9)!important;box-shadow:0 0 28px rgba(255,255,255,0.5)!important;filter:brightness(2.2);}\n  .tile.flash-active::after{opacity:1;}\n  .tile.tap-correct{border-color:var(--green)!important;box-shadow:0 0 20px rgba(0,232,138,0.6)!important;filter:brightness(1.6);}\n  .tile.tap-wrong{border-color:var(--pink)!important;box-shadow:0 0 20px rgba(255,45,120,0.6)!important;filter:brightness(1.4);}\n\n  .progress-row{display:flex;gap:6px;justify-content:center;margin-top:16px;}\n  .prog-dot{width:10px;height:10px;border-radius:50%;border:1px solid var(--border);background:transparent;transition:all 0.2s;}\n  .prog-dot.done{background:var(--green);border-color:var(--green);box-shadow:0 0 8px rgba(0,232,138,0.5);}\n  .prog-dot.active{background:var(--cyan);border-color:var(--cyan);box-shadow:0 0 8px rgba(0,245,255,0.5);}\n\n  .level-badge{text-align:center;margin-bottom:16px;}\n  .level-text{font-family:\'Orbitron\',monospace;font-size:11px;letter-spacing:3px;color:var(--muted);text-transform:uppercase;}\n  .level-num{font-family:\'Orbitron\',monospace;font-size:20px;font-weight:900;color:var(--purple);}\n\n  .start-btn{display:block;width:100%;margin-top:16px;padding:14px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:10px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.25s;}\n  .start-btn:hover{box-shadow:0 6px 20px rgba(181,55,242,0.5);transform:translateY(-2px);}\n  .start-btn:disabled{opacity:0.4;cursor:default;transform:none;box-shadow:none;}\n\n  .overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:200;align-items:center;justify-content:center;}\n  .overlay.show{display:flex;}\n  .result-card{background:rgba(15,10,40,0.98);border:1px solid var(--purple);border-radius:20px;padding:48px 40px;text-align:center;max-width:360px;width:90%;}\n  .result-card h2{font-family:\'Orbitron\',monospace;font-size:22px;color:var(--cyan);margin-bottom:8px;}\n  .result-score{font-family:\'Orbitron\',monospace;font-size:56px;font-weight:900;background:linear-gradient(135deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin:16px 0;}\n  .result-meta{color:var(--muted);font-size:14px;margin-bottom:6px;}\n  .result-btn{display:inline-block;padding:14px 32px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:16px;}\n  .result-btn-sec{display:inline-block;padding:14px 32px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:8px;margin-left:8px;}\n  .result-btn-sec:hover{border-color:var(--cyan);color:var(--cyan);}\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── INSTRUCTIONS STRIP ── */\n  .instr-strip{background:rgba(15,10,40,0.85);border:1px solid rgba(0,245,255,0.2);border-radius:12px;padding:14px 20px;margin-bottom:20px;display:flex;gap:10px;flex-wrap:wrap;align-items:flex-start;}\n  .instr-strip-title{font-family:\'Orbitron\',monospace;font-size:10px;letter-spacing:2px;color:var(--cyan);text-transform:uppercase;margin-bottom:8px;display:block;}\n  .instr-steps{display:flex;flex-wrap:wrap;gap:8px;width:100%;}\n  .instr-step{display:flex;align-items:center;gap:6px;background:rgba(255,255,255,0.04);border:1px solid rgba(181,55,242,0.18);border-radius:8px;padding:6px 10px;font-size:12px;color:var(--text);line-height:1.4;}\n  .instr-step .i-num{font-family:\'Orbitron\',monospace;font-size:9px;font-weight:700;color:var(--cyan);background:rgba(0,245,255,0.1);border-radius:4px;padding:2px 5px;flex-shrink:0;}\n  .instr-step .i-icon{font-size:14px;flex-shrink:0;}\n  .instr-step strong{color:var(--cyan);}\n\n</style>\n</head>\n<body>\n<nav>\n  <div class="nav-logo">MINDBOOST</div>\n  <div style="display:flex;gap:8px;">\n    <a href="/dashboard" class="nav-btn">Dashboard</a>\n    <a href="/play" class="nav-btn">← Games</a>\n  </div>\n</nav>\n\n<div class="container">\n  <div class="hud">\n    <div class="hud-item"><div class="hud-label">Score</div>\n<!-- INSTR-INJECTED -->\n<div class="instr-strip">\n  <span class="instr-strip-title">📖 How to Play</span>\n  <div class="instr-steps">\n    <div class="instr-step"><span class="i-num">1</span><span class="i-icon">👁️</span>Tiles flash in a sequence — <strong>watch and memorize</strong> the order</div>\n    <div class="instr-step"><span class="i-num">2</span><span class="i-icon">☝️</span>Tap the tiles back in the <strong>exact same order</strong></div>\n    <div class="instr-step"><span class="i-num">3</span><span class="i-icon">📈</span>Each correct round adds <strong>one more tile</strong> to the sequence</div>\n    <div class="instr-step"><span class="i-num">4</span><span class="i-icon">❤️</span>You have <strong>3 lives</strong> — a wrong tap costs one</div>\n  </div>\n</div><div class="hud-value" id="score">0</div></div>\n    <div class="hud-item"><div class="hud-label">🧠 Sequence Tap</div><div style="color:var(--muted);font-size:12px;margin-top:4px;">Watch, then repeat!</div></div>\n    <div class="hud-item"><div class="hud-label">Best</div><div class="hud-value" id="best">0</div></div>\n    <div class="hud-item"><div class="hud-label">Time</div><div class="hud-value" id="timer">60</div></div>\n  </div>\n\n  <div class="level-badge">\n    <div class="level-text">SEQUENCE LENGTH</div>\n    <div class="level-num" id="level-num">—</div>\n  </div>\n\n  <div class="status-bar">\n    <div class="status-text status-watch" id="status-text">PRESS START TO PLAY</div>\n  </div>\n\n  <div class="board-wrap">\n    <div class="grid" id="grid"></div>\n    <div class="progress-row" id="progress-row"></div>\n    <button class="start-btn" id="start-btn" onclick="startRound()">▶ START GAME</button>\n  </div>\n</div>\n\n<div class="overlay" id="overlay">\n  <div class="result-card">\n    <h2>GAME OVER</h2>\n    <div class="result-score" id="final-score">0</div>\n    <div class="result-meta">Final Score</div>\n    <div class="result-meta" id="final-level" style="margin-top:4px;"></div>\n    <a href="/play" class="result-btn">BACK TO GAMES</a>\n    <button class="result-btn-sec" onclick="restartGame()">TRY AGAIN</button>\n  </div>\n</div>\n\n<script>\nconst EMOJIS = [\'🔴\',\'🔵\',\'🟢\',\'🟡\',\'🟣\',\'🟠\',\'⚪\',\'🩷\',\'🩵\'];\nconst TILES  = 9;\n\nlet sequence      = [];\nlet playerSeq     = [];\nlet level         = 1;\nlet score         = 0;\nlet best          = 0;\nlet phase         = \'idle\'; // idle | showing | input\nlet lives         = 3;\nlet correct       = 0;\nlet attempts      = 0;\nlet gameActive    = false;\nlet startTime     = null;\nlet timeLeft      = 60;\nlet timerRef      = null;\n\nfunction buildGrid() {\n  const g = document.getElementById(\'grid\');\n  g.innerHTML = \'\';\n  for (let i = 0; i < TILES; i++) {\n    const d = document.createElement(\'div\');\n    d.className = `tile tile-${i} locked`;\n    d.dataset.i = i;\n    d.textContent = EMOJIS[i];\n    d.onclick = () => playerTap(i);\n    g.appendChild(d);\n  }\n}\n\nfunction setStatus(text, cls) {\n  const el = document.getElementById(\'status-text\');\n  el.textContent = text;\n  el.className = \'status-text \' + cls;\n}\n\nfunction flashTile(idx, duration = 420) {\n  return new Promise(res => {\n    const el = document.querySelector(`.tile[data-i="${idx}"]`);\n    el.classList.add(\'flash-active\');\n    setTimeout(() => { el.classList.remove(\'flash-active\'); setTimeout(res, 80); }, duration);\n  });\n}\n\nfunction buildProgress() {\n  const row = document.getElementById(\'progress-row\');\n  row.innerHTML = \'\';\n  for (let i = 0; i < sequence.length; i++) {\n    const d = document.createElement(\'div\');\n    d.className = \'prog-dot\' + (i < playerSeq.length ? \' done\' : i === playerSeq.length ? \' active\' : \'\');\n    row.appendChild(d);\n  }\n}\n\nasync function showSequence() {\n  phase = \'showing\';\n  setTilesLocked(true);\n  setStatus(`WATCH THE SEQUENCE  (${sequence.length} tiles)`, \'status-watch\');\n\n  // small pause before showing\n  await delay(600);\n\n  // flash speed increases with level\n  const flashDur = Math.max(250, 500 - level * 20);\n  const gapDur   = Math.max(100, 300 - level * 10);\n\n  for (const idx of sequence) {\n    await flashTile(idx, flashDur);\n    await delay(gapDur);\n  }\n\n  await delay(300);\n  phase = \'input\';\n  setTilesLocked(false);\n  setStatus(\'YOUR TURN — TAP THE SEQUENCE!\', \'status-go\');\n  buildProgress();\n}\n\nfunction setTilesLocked(locked) {\n  document.querySelectorAll(\'.tile\').forEach(t => {\n    if (locked) t.classList.add(\'locked\');\n    else        t.classList.remove(\'locked\');\n  });\n}\n\nasync function playerTap(idx) {\n  if (phase !== \'input\' || !gameActive) return;\n\n  attempts++;\n  playerSeq.push(idx);\n  const step = playerSeq.length - 1;\n\n  if (playerSeq[step] === sequence[step]) {\n    // correct tap\n    correct++;\n    const el = document.querySelector(`.tile[data-i="${idx}"]`);\n    el.classList.add(\'tap-correct\');\n    setTimeout(() => el.classList.remove(\'tap-correct\'), 300);\n    buildProgress();\n\n    if (playerSeq.length === sequence.length) {\n      // completed sequence!\n      const bonus = level * 10;\n      score += bonus;\n      if (score > best) { best = score; document.getElementById(\'best\').textContent = best; }\n      document.getElementById(\'score\').textContent = score;\n      setStatus(`✓ CORRECT! +${bonus} pts`, \'status-correct\');\n      await delay(700);\n      level++;\n      document.getElementById(\'level-num\').textContent = level;\n      nextRound();\n    }\n  } else {\n    // wrong tap\n    lives--;\n    const el = document.querySelector(`.tile[data-i="${idx}"]`);\n    el.classList.add(\'tap-wrong\');\n    setTimeout(() => el.classList.remove(\'tap-wrong\'), 400);\n    setStatus(`✗ WRONG!  ${lives} ${lives === 1 ? \'life\' : \'lives\'} left`, \'status-wrong\');\n\n    if (lives <= 0) {\n      await delay(700);\n      endGame();\n    } else {\n      // replay same sequence\n      await delay(900);\n      playerSeq = [];\n      showSequence();\n    }\n  }\n}\n\nfunction nextRound() {\n  sequence.push(Math.floor(Math.random() * TILES));\n  playerSeq = [];\n  showSequence();\n}\n\nfunction startRound() {\n  if (gameActive) return;\n  gameActive = true;\n  startTime  = Date.now();\n  level      = 1;\n  score      = 0;\n  lives      = 3;\n  correct    = 0;\n  attempts   = 0;\n  timeLeft   = 60;\n  sequence   = [Math.floor(Math.random() * TILES)];\n  playerSeq  = [];\n  document.getElementById(\'score\').textContent    = 0;\n  document.getElementById(\'level-num\').textContent = level;\n  document.getElementById(\'timer\').textContent    = 60;\n  document.getElementById(\'start-btn\').disabled   = true;\n\n  timerRef = setInterval(() => {\n    if (!gameActive) { clearInterval(timerRef); return; }\n    timeLeft--;\n    document.getElementById(\'timer\').textContent = timeLeft;\n    if (timeLeft <= 0) {\n      gameActive = false;\n      clearInterval(timerRef);\n      phase = \'idle\';\n      setTilesLocked(true);\n      const elapsed = 60;\n      const acc = attempts > 0 ? Math.round(correct / attempts * 100) : 0;\n      document.getElementById(\'final-score\').textContent = score;\n      document.getElementById(\'final-level\').textContent = `Sequence Length: ${sequence.length}  ·  Accuracy: ${acc}%`;\n      document.getElementById(\'overlay\').classList.add(\'show\');\n      document.getElementById(\'start-btn\').disabled = false;\n      fetch(\'/save_score\', {\n        method: \'POST\',\n        headers: { \'Content-Type\': \'application/json\' },\n        body: JSON.stringify({ game_name: \'Sequence Tap\', score, time_taken: elapsed, accuracy: acc })\n      });\n    }\n  }, 1000);\n\n  showSequence();\n}\n\nfunction endGame() {\n  gameActive = false;\n  phase      = \'idle\';\n  clearInterval(timerRef);\n  const elapsed = Math.round((Date.now() - startTime) / 1000);\n  const acc     = attempts > 0 ? Math.round(correct / attempts * 100) : 0;\n  setTilesLocked(true);\n  setStatus(\'GAME OVER\', \'status-wrong\');\n  document.getElementById(\'final-score\').textContent = score;\n  document.getElementById(\'final-level\').textContent  = `Sequence Length: ${sequence.length}  ·  Accuracy: ${acc}%`;\n  document.getElementById(\'overlay\').classList.add(\'show\');\n  document.getElementById(\'start-btn\').disabled = false;\n  fetch(\'/save_score\', {\n    method: \'POST\',\n    headers: { \'Content-Type\': \'application/json\' },\n    body: JSON.stringify({ game_name: \'Sequence Tap\', score, time_taken: elapsed, accuracy: acc })\n  });\n}\n\nfunction restartGame() {\n  document.getElementById(\'overlay\').classList.remove(\'show\');\n  document.getElementById(\'progress-row\').innerHTML = \'\';\n  document.getElementById(\'level-num\').textContent   = \'—\';\n  document.getElementById(\'timer\').textContent       = \'60\';\n  setStatus(\'PRESS START TO PLAY\', \'status-watch\');\n  startRound();\n}\n\nfunction delay(ms) { return new Promise(r => setTimeout(r, ms)); }\n\nbuildGrid();\n</script>\n\n<!-- HTP-INJECTED -->\n<!-- HOW TO PLAY BUTTON -->\n<button class="htp-btn" onclick="document.getElementById(\'htp-modal\').classList.add(\'open\')" title="How to Play">❓</button>\n\n<!-- HOW TO PLAY MODAL -->\n<div class="htp-overlay" id="htp-modal">\n  <div class="htp-box">\n    <div class="htp-header">\n      <div class="htp-title">SEQUENCE TAP</div>\n      <div class="htp-sub">Watch the pattern, then repeat it exactly</div>\n      <button class="htp-close" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">✕</button>\n    </div>\n    <div class="htp-body">\n      <ol class="htp-steps">\n        <li class="htp-step"><div class="htp-num">1</div><div class="htp-text">👁️ Tiles light up one by one — <strong>watch and memorize</strong> the sequence.</div></li>\n        <li class="htp-step"><div class="htp-num">2</div><div class="htp-text">☝️ After the sequence plays, tap the tiles <strong>in the exact same order</strong>.</div></li>\n        <li class="htp-step"><div class="htp-num">3</div><div class="htp-text">📈 Get it right and the sequence <strong>gets one tile longer</strong> each round.</div></li>\n        <li class="htp-step"><div class="htp-num">4</div><div class="htp-text">❤️ You have <strong>3 lives</strong> — a wrong tap costs a life. Run out and it\'s game over.</div></li>\n        <li class="htp-step"><div class="htp-num">5</div><div class="htp-text">🏆 Score increases with each level. <strong>How far can you go?</strong></div></li>\n      </ol>\n      <div class="htp-tip">💡 <span>Pro tip:</span> Mentally group the tiles into chunks of 2–3 for easier recall!</div>\n    </div>\n    <div class="htp-footer">\n      <button class="htp-go" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">GOT IT — LET\'S PLAY!</button>\n    </div>\n  </div>\n</div>\n<script>\n(function(){\n  var ov=document.getElementById(\'htp-modal\');\n  ov.addEventListener(\'click\',function(e){if(e.target===this)this.classList.remove(\'open\');});\n  document.addEventListener(\'keydown\',function(e){if(e.key===\'Escape\')ov.classList.remove(\'open\');});\n})();\n</script>\n\n</body>\n</html>'

REFLEX_TAP_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>MindBoost — Reflex Tap</title>\n<link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@700;900&family=Rajdhani:wght@400;600&display=swap" rel="stylesheet">\n<style>\n  :root{--purple:#b537f2;--cyan:#00f5ff;--pink:#ff2d78;--green:#00e88a;--orange:#ff9f43;--bg:#050510;--border:rgba(181,55,242,0.3);--text:#e8e0ff;--muted:#7a6f9a;}\n  *{margin:0;padding:0;box-sizing:border-box;}\n  body{font-family:\'Rajdhani\',sans-serif;background:var(--bg);color:var(--text);min-height:100vh;}\n  body::before{content:\'\';position:fixed;inset:0;pointer-events:none;background-image:linear-gradient(rgba(181,55,242,0.05) 1px,transparent 1px),linear-gradient(90deg,rgba(181,55,242,0.05) 1px,transparent 1px);background-size:40px 40px;}\n  nav{display:flex;align-items:center;justify-content:space-between;padding:14px 28px;border-bottom:1px solid var(--border);background:rgba(5,5,16,0.95);backdrop-filter:blur(16px);}\n  .nav-logo{font-family:\'Orbitron\',monospace;font-size:16px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;}\n  .nav-btn{padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--text);font-family:\'Rajdhani\',sans-serif;font-size:13px;font-weight:600;border-radius:6px;cursor:pointer;transition:all 0.2s;text-decoration:none;display:inline-block;letter-spacing:1px;}\n  .nav-btn:hover{background:rgba(181,55,242,0.2);border-color:var(--purple);color:var(--cyan);}\n  .container{max-width:640px;margin:0 auto;padding:24px 20px;position:relative;z-index:1;}\n\n  .hud{display:flex;justify-content:space-between;align-items:center;background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:12px;padding:14px 22px;margin-bottom:16px;}\n  .hud-item{text-align:center;}\n  .hud-label{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);}\n  .hud-value{font-family:\'Orbitron\',monospace;font-size:26px;font-weight:900;color:var(--cyan);}\n  .hud-value.warn{color:var(--orange);}\n  .hud-value.danger{color:var(--pink);animation:blink 0.5s infinite;}\n  @keyframes blink{0%,100%{opacity:1}50%{opacity:0.4}}\n\n  .board-wrap{background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:16px;padding:20px;}\n\n  /* reaction meter */\n  .reaction-bar{display:flex;align-items:center;gap:12px;margin-bottom:16px;}\n  .r-label{font-size:11px;letter-spacing:2px;color:var(--muted);white-space:nowrap;}\n  .r-track{flex:1;height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;}\n  .r-fill{height:100%;width:0%;border-radius:3px;transition:width 0.08s linear;background:var(--green);}\n  .r-time{font-family:\'Orbitron\',monospace;font-size:12px;color:var(--cyan);min-width:52px;text-align:right;}\n\n  /* grid */\n  #grid{\n    display:grid;\n    grid-template-columns:repeat(4,1fr);\n    gap:10px;\n    margin-bottom:16px;\n  }\n\n  .zone{\n    aspect-ratio:1;\n    border-radius:14px;\n    background:rgba(255,255,255,0.04);\n    border:2px solid rgba(255,255,255,0.07);\n    cursor:pointer;\n    transition:transform 0.1s, background 0.08s, border-color 0.08s;\n    position:relative;\n    overflow:hidden;\n    display:flex;align-items:center;justify-content:center;\n  }\n  .zone:hover{transform:scale(0.97);}\n  .zone:active{transform:scale(0.92);}\n\n  /* lit state — colour coded by speed */\n  .zone.lit-fast{\n    background:rgba(0,232,138,0.25);\n    border-color:var(--green);\n    box-shadow:0 0 18px rgba(0,232,138,0.5), inset 0 0 14px rgba(0,232,138,0.2);\n    animation:pulse-fast 0.25s ease-in-out infinite alternate;\n  }\n  .zone.lit-med{\n    background:rgba(0,245,255,0.2);\n    border-color:var(--cyan);\n    box-shadow:0 0 18px rgba(0,245,255,0.4), inset 0 0 14px rgba(0,245,255,0.15);\n    animation:pulse-med 0.4s ease-in-out infinite alternate;\n  }\n  .zone.lit-slow{\n    background:rgba(255,159,67,0.2);\n    border-color:var(--orange);\n    box-shadow:0 0 18px rgba(255,159,67,0.4), inset 0 0 14px rgba(255,159,67,0.15);\n    animation:pulse-slow 0.6s ease-in-out infinite alternate;\n  }\n  @keyframes pulse-fast{from{box-shadow:0 0 14px rgba(0,232,138,0.4)}to{box-shadow:0 0 28px rgba(0,232,138,0.8)}}\n  @keyframes pulse-med{from{box-shadow:0 0 14px rgba(0,245,255,0.3)}to{box-shadow:0 0 28px rgba(0,245,255,0.7)}}\n  @keyframes pulse-slow{from{box-shadow:0 0 14px rgba(255,159,67,0.3)}to{box-shadow:0 0 28px rgba(255,159,67,0.7)}}\n\n  /* shrink ring inside lit zone */\n  .zone.lit-fast::before,.zone.lit-med::before,.zone.lit-slow::before{\n    content:\'\';position:absolute;border-radius:50%;\n    border:2px solid rgba(255,255,255,0.6);\n    animation:shrinkRing var(--ring-dur,0.6s) linear forwards;\n  }\n  @keyframes shrinkRing{\n    0%{width:90%;height:90%;opacity:0.8;}\n    100%{width:10%;height:10%;opacity:0;}\n  }\n\n  /* hit flash */\n  .zone.hit{\n    background:rgba(0,232,138,0.4)!important;\n    border-color:var(--green)!important;\n    animation:hitFlash 0.3s ease forwards!important;\n  }\n  @keyframes hitFlash{0%{transform:scale(1.08)}100%{transform:scale(1);opacity:0.3}}\n\n  /* miss flash */\n  .zone.miss-flash{\n    background:rgba(255,45,120,0.25)!important;\n    border-color:var(--pink)!important;\n  }\n\n  /* score popup */\n  .score-popup{\n    position:fixed;font-family:\'Orbitron\',monospace;font-size:16px;font-weight:900;\n    pointer-events:none;z-index:999;transform:translateX(-50%);\n    animation:floatUp 0.9s ease forwards;\n  }\n  @keyframes floatUp{0%{opacity:1;transform:translateX(-50%) translateY(0)}100%{opacity:0;transform:translateX(-50%) translateY(-60px)}}\n\n  /* feedback strip */\n  .feedback{\n    text-align:center;height:28px;margin-bottom:10px;\n    font-family:\'Orbitron\',monospace;font-size:12px;letter-spacing:2px;\n    transition:color 0.2s;color:var(--muted);\n  }\n\n  /* lives */\n  .lives-row{display:flex;justify-content:center;gap:8px;margin-bottom:14px;}\n  .life{font-size:20px;transition:all 0.3s;}\n  .life.lost{filter:grayscale(1);opacity:0.25;transform:scale(0.8);}\n\n  .start-btn{display:block;width:100%;padding:13px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:10px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.25s;}\n  .start-btn:hover{box-shadow:0 6px 20px rgba(181,55,242,0.5);transform:translateY(-2px);}\n  .start-btn:disabled{opacity:0.4;cursor:default;transform:none;box-shadow:none;}\n\n  .overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.78);z-index:200;align-items:center;justify-content:center;}\n  .overlay.show{display:flex;}\n  .result-card{background:rgba(15,10,40,0.98);border:1px solid var(--purple);border-radius:20px;padding:44px 40px;text-align:center;max-width:380px;width:90%;}\n  .result-card h2{font-family:\'Orbitron\',monospace;font-size:22px;color:var(--cyan);margin-bottom:8px;}\n  .result-score{font-family:\'Orbitron\',monospace;font-size:56px;font-weight:900;background:linear-gradient(135deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin:14px 0;}\n  .result-meta{color:var(--muted);font-size:14px;margin-bottom:4px;}\n  .result-stats{display:flex;gap:20px;justify-content:center;margin:16px 0;}\n  .r-stat-val{font-family:\'Orbitron\',monospace;font-size:22px;font-weight:900;color:var(--cyan);}\n  .r-stat-lbl{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);margin-top:2px;}\n  .result-btn{display:inline-block;padding:13px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:12px;}\n  .result-btn-sec{display:inline-block;padding:13px 28px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:8px;margin-left:8px;}\n  .result-btn-sec:hover{border-color:var(--cyan);color:var(--cyan);}\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── INSTRUCTIONS STRIP ── */\n  .instr-strip{background:rgba(15,10,40,0.85);border:1px solid rgba(0,245,255,0.2);border-radius:12px;padding:14px 20px;margin-bottom:20px;display:flex;gap:10px;flex-wrap:wrap;align-items:flex-start;}\n  .instr-strip-title{font-family:\'Orbitron\',monospace;font-size:10px;letter-spacing:2px;color:var(--cyan);text-transform:uppercase;margin-bottom:8px;display:block;}\n  .instr-steps{display:flex;flex-wrap:wrap;gap:8px;width:100%;}\n  .instr-step{display:flex;align-items:center;gap:6px;background:rgba(255,255,255,0.04);border:1px solid rgba(181,55,242,0.18);border-radius:8px;padding:6px 10px;font-size:12px;color:var(--text);line-height:1.4;}\n  .instr-step .i-num{font-family:\'Orbitron\',monospace;font-size:9px;font-weight:700;color:var(--cyan);background:rgba(0,245,255,0.1);border-radius:4px;padding:2px 5px;flex-shrink:0;}\n  .instr-step .i-icon{font-size:14px;flex-shrink:0;}\n  .instr-step strong{color:var(--cyan);}\n\n</style>\n</head>\n<body>\n<nav>\n  <div class="nav-logo">MINDBOOST</div>\n  <div style="display:flex;gap:8px;">\n    <a href="/dashboard" class="nav-btn">Dashboard</a>\n    <a href="/play" class="nav-btn">← Games</a>\n  </div>\n</nav>\n\n<div class="container">\n  <div class="hud">\n    <div class="hud-item"><div class="hud-label">Score</div>\n<!-- INSTR-INJECTED -->\n<div class="instr-strip">\n  <span class="instr-strip-title">📖 How to Play</span>\n  <div class="instr-steps">\n    <div class="instr-step"><span class="i-num">1</span><span class="i-icon">⚡</span>A <strong>random cell lights up</strong> on the grid — tap it fast!</div>\n    <div class="instr-step"><span class="i-num">2</span><span class="i-icon">⏱️</span>Points are based on your <strong>reaction speed</strong> — faster = more</div>\n    <div class="instr-step"><span class="i-num">3</span><span class="i-icon">❌</span>Missing or tapping the wrong cell <strong>costs a life</strong></div>\n    <div class="instr-step"><span class="i-num">4</span><span class="i-icon">🚀</span>Zones fade <strong>faster as your score grows</strong> — survive as long as you can</div>\n  </div>\n</div><div class="hud-value" id="score">0</div></div>\n    <div class="hud-item"><div class="hud-label">⚡ Reflex Tap</div><div style="color:var(--muted);font-size:12px;margin-top:4px;">Tap the zone before it fades!</div></div>\n    <div class="hud-item"><div class="hud-label">Hits</div><div class="hud-value" id="hits">0</div></div>\n    <div class="hud-item"><div class="hud-label">Time</div><div class="hud-value" id="timer">60</div></div>\n  </div>\n\n  <div class="board-wrap">\n    <div class="reaction-bar">\n      <span class="r-label">REACTION</span>\n      <div class="r-track"><div class="r-fill" id="r-fill"></div></div>\n      <span class="r-time" id="r-time">—</span>\n    </div>\n\n    <div class="lives-row" id="lives-row"></div>\n    <div class="feedback" id="feedback">Press START to begin</div>\n\n    <div id="grid"></div>\n\n    <button class="start-btn" id="start-btn" onclick="startGame()">▶ START GAME</button>\n  </div>\n</div>\n\n<div class="overlay" id="overlay">\n  <div class="result-card">\n    <h2 id="result-title">TIME\'S UP!</h2>\n    <div class="result-score" id="final-score">0</div>\n    <div class="result-meta">Final Score</div>\n    <div class="result-stats">\n      <div style="text-align:center"><div class="r-stat-val" id="final-hits">0</div><div class="r-stat-lbl">Hits</div></div>\n      <div style="text-align:center"><div class="r-stat-val" id="final-acc">0%</div><div class="r-stat-lbl">Accuracy</div></div>\n      <div style="text-align:center"><div class="r-stat-val" id="final-avg">0ms</div><div class="r-stat-lbl">Avg Reaction</div></div>\n    </div>\n    <a href="/play" class="result-btn">BACK TO GAMES</a>\n    <button class="result-btn-sec" onclick="restartGame()">TRY AGAIN</button>\n  </div>\n</div>\n\n<script>\nconst COLS      = 4;\nconst ROWS      = 4;\nconst ZONES     = COLS * ROWS;\nconst MAX_LIVES = 3;\n\nlet score       = 0;\nlet hits        = 0;\nlet misses      = 0;\nlet timeLeft    = 60;\nlet lives       = MAX_LIVES;\nlet active      = false;\nlet litZone     = -1;\nlet litTimeout  = null;\nlet timerRef    = null;\nlet litStart    = 0;\nlet totalRT     = 0;\nlet rtCount     = 0;\nlet streak      = 0;\nlet bestStreak  = 0;\nlet round       = 0;\n\n// difficulty ramp: window shrinks as score grows\nfunction getWindow() {\n  if (score < 200)  return 1800;\n  if (score < 500)  return 1400;\n  if (score < 900)  return 1100;\n  if (score < 1400) return 850;\n  return 650;\n}\nfunction getDelay() {\n  // gap between zones\n  if (score < 300)  return 700 + Math.random() * 500;\n  if (score < 800)  return 450 + Math.random() * 350;\n  return 280 + Math.random() * 250;\n}\nfunction getLitClass(win) {\n  if (win <= 800)  return \'lit-fast\';\n  if (win <= 1200) return \'lit-med\';\n  return \'lit-slow\';\n}\n\n// Build grid\nfunction buildGrid() {\n  const g = document.getElementById(\'grid\');\n  g.innerHTML = \'\';\n  for (let i = 0; i < ZONES; i++) {\n    const z = document.createElement(\'div\');\n    z.className  = \'zone\';\n    z.dataset.idx = i;\n    z.onclick = () => onZoneClick(i);\n    g.appendChild(z);\n  }\n}\n\nfunction buildLives() {\n  const row = document.getElementById(\'lives-row\');\n  row.innerHTML = \'\';\n  for (let i = 0; i < MAX_LIVES; i++) {\n    const d = document.createElement(\'div\');\n    d.className = \'life\' + (i >= lives ? \' lost\' : \'\');\n    d.textContent = \'⚡\';\n    row.appendChild(d);\n  }\n}\n\nfunction setFeedback(text, color) {\n  const el = document.getElementById(\'feedback\');\n  el.textContent = text;\n  el.style.color  = color || \'var(--muted)\';\n}\n\nfunction showReaction(ms) {\n  const el   = document.getElementById(\'r-time\');\n  const fill = document.getElementById(\'r-fill\');\n  el.textContent = ms + \'ms\';\n  // fill bar: 200ms = 100%, 800ms = 0%\n  const pct = Math.max(0, Math.min(100, (1 - (ms - 200) / 600) * 100));\n  fill.style.width = pct + \'%\';\n  fill.style.background = pct > 60 ? \'var(--green)\' : pct > 30 ? \'var(--orange)\' : \'var(--pink)\';\n}\n\nfunction spawnPopup(text, color, zoneIdx) {\n  const zones = document.querySelectorAll(\'.zone\');\n  const rect  = zones[zoneIdx].getBoundingClientRect();\n  const el    = document.createElement(\'div\');\n  el.className   = \'score-popup\';\n  el.textContent = text;\n  el.style.color = color;\n  el.style.left  = (rect.left + rect.width / 2) + \'px\';\n  el.style.top   = rect.top + \'px\';\n  document.body.appendChild(el);\n  setTimeout(() => el.remove(), 900);\n}\n\nfunction lightZone() {\n  if (!active) return;\n  round++;\n  const win   = getWindow();\n  const cls   = getLitClass(win);\n  const idx   = Math.floor(Math.random() * ZONES);\n  const zones = document.querySelectorAll(\'.zone\');\n\n  litZone = idx;\n  litStart = performance.now();\n\n  const z = zones[idx];\n  z.style.setProperty(\'--ring-dur\', win + \'ms\');\n  z.classList.add(cls);\n\n  litTimeout = setTimeout(() => {\n    if (!active) return;\n    // zone expired — miss\n    zones[idx].classList.remove(cls);\n    zones[idx].classList.add(\'miss-flash\');\n    setTimeout(() => zones[idx].classList.remove(\'miss-flash\'), 300);\n    litZone = -1;\n    misses++;\n    streak  = 0;\n    lives--;\n    buildLives();\n    setFeedback(\'TOO SLOW! ⚡ lost\', \'var(--pink)\');\n    if (lives <= 0) { endGame(true); return; }\n    setTimeout(lightZone, getDelay());\n  }, win);\n}\n\nfunction onZoneClick(idx) {\n  if (!active) return;\n  const zones = document.querySelectorAll(\'.zone\');\n\n  if (idx === litZone) {\n    // HIT\n    clearTimeout(litTimeout);\n    const rt   = Math.round(performance.now() - litStart);\n    const win  = getWindow();\n    totalRT   += rt;\n    rtCount++;\n    hits++;\n    streak++;\n    if (streak > bestStreak) bestStreak = streak;\n\n    // remove lit class\n    zones[idx].className = \'zone hit\';\n    setTimeout(() => zones[idx].className = \'zone\', 300);\n\n    // score: faster = more pts, streak multiplier\n    const speedPts  = Math.round(Math.max(10, (1 - rt / win) * 80));\n    const streakMul = streak >= 5 ? 3 : streak >= 3 ? 2 : 1;\n    const pts       = speedPts * streakMul;\n    score += pts;\n    litZone = -1;\n\n    document.getElementById(\'score\').textContent = score;\n    document.getElementById(\'hits\').textContent  = hits;\n    showReaction(rt);\n\n    const msg = streak >= 5 ? `🔥${streak}x +${pts}` : streak >= 3 ? `⚡${streak}x +${pts}` : `+${pts}`;\n    const col = rt < 300 ? \'var(--green)\' : rt < 500 ? \'var(--cyan)\' : \'var(--orange)\';\n    spawnPopup(msg, col, idx);\n\n    const fb = rt < 300 ? \'⚡ LIGHTNING!\' : rt < 500 ? \'✓ FAST!\' : rt < 700 ? \'~ GOOD\' : \'~ OK\';\n    setFeedback(fb + (streak >= 3 ? `  🔥 ${streak}x STREAK` : \'\'), col);\n\n    setTimeout(lightZone, getDelay());\n  } else {\n    // wrong zone click — no penalty, just ignore\n    zones[idx].classList.add(\'miss-flash\');\n    setTimeout(() => zones[idx].classList.remove(\'miss-flash\'), 200);\n  }\n}\n\nfunction startGame() {\n  buildGrid();\n  lives     = MAX_LIVES;\n  score     = 0; hits = 0; misses = 0;\n  timeLeft  = 60;\n  streak    = 0; bestStreak = 0; round = 0;\n  totalRT   = 0; rtCount = 0;\n  active    = true;\n\n  document.getElementById(\'score\').textContent   = 0;\n  document.getElementById(\'hits\').textContent    = 0;\n  document.getElementById(\'r-time\').textContent  = \'—\';\n  document.getElementById(\'r-fill\').style.width  = \'0%\';\n  document.getElementById(\'start-btn\').disabled  = true;\n  buildLives();\n  setFeedback(\'GET READY…\', \'var(--cyan)\');\n\n  setTimeout(() => {\n    setFeedback(\'TAP THE GLOWING ZONE!\', \'var(--muted)\');\n    lightZone();\n  }, 800);\n\n  timerRef = setInterval(() => {\n    if (!active) { clearInterval(timerRef); return; }\n    timeLeft--;\n    const el = document.getElementById(\'timer\');\n    el.textContent = timeLeft;\n    el.className   = \'hud-value\' + (timeLeft <= 10 ? \' danger\' : timeLeft <= 20 ? \' warn\' : \'\');\n    if (timeLeft === 0) endGame(false);\n  }, 1000);\n}\n\nfunction endGame(outOfLives) {\n  active = false;\n  clearTimeout(litTimeout);\n  clearInterval(timerRef);\n\n  // clear any lit zones\n  document.querySelectorAll(\'.zone\').forEach(z => z.className = \'zone\');\n\n  const acc    = (hits + misses) > 0 ? Math.round(hits / (hits + misses) * 100) : 0;\n  const avgRT  = rtCount > 0 ? Math.round(totalRT / rtCount) : 0;\n\n  document.getElementById(\'result-title\').textContent  = outOfLives ? \'OUT OF LIVES!\' : "TIME\'S UP!";\n  document.getElementById(\'final-score\').textContent   = score;\n  document.getElementById(\'final-hits\').textContent    = hits;\n  document.getElementById(\'final-acc\').textContent     = acc + \'%\';\n  document.getElementById(\'final-avg\').textContent     = avgRT + \'ms\';\n  document.getElementById(\'overlay\').classList.add(\'show\');\n\n  fetch(\'/save_score\', {\n    method: \'POST\',\n    headers: {\'Content-Type\':\'application/json\'},\n    body: JSON.stringify({game_name:\'Reflex Tap\', score, time_taken: 60 - timeLeft, accuracy: acc})\n  });\n}\n\nfunction restartGame() {\n  document.getElementById(\'overlay\').classList.remove(\'show\');\n  document.getElementById(\'start-btn\').disabled  = false;\n  document.getElementById(\'timer\').className     = \'hud-value\';\n  document.getElementById(\'timer\').textContent   = 60;\n  setFeedback(\'Press START to begin\', \'var(--muted)\');\n  startGame();\n}\n\nbuildGrid();\n</script>\n\n<!-- HTP-INJECTED -->\n<!-- HOW TO PLAY BUTTON -->\n<button class="htp-btn" onclick="document.getElementById(\'htp-modal\').classList.add(\'open\')" title="How to Play">❓</button>\n\n<!-- HOW TO PLAY MODAL -->\n<div class="htp-overlay" id="htp-modal">\n  <div class="htp-box">\n    <div class="htp-header">\n      <div class="htp-title">REFLEX TAP</div>\n      <div class="htp-sub">Tap the lit zone before it fades</div>\n      <button class="htp-close" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">✕</button>\n    </div>\n    <div class="htp-body">\n      <ol class="htp-steps">\n        <li class="htp-step"><div class="htp-num">1</div><div class="htp-text">⚡ A <strong>random zone</strong> on the grid lights up — tap it as fast as you can!</div></li>\n        <li class="htp-step"><div class="htp-num">2</div><div class="htp-text">⏱️ Each successful tap scores points based on your <strong>reaction speed</strong>.</div></li>\n        <li class="htp-step"><div class="htp-num">3</div><div class="htp-text">❌ Missing a zone or tapping the <strong>wrong cell costs you a life</strong>.</div></li>\n        <li class="htp-step"><div class="htp-num">4</div><div class="htp-text">🚀 The zones fade <strong>faster as your score climbs</strong> — stay sharp!</div></li>\n        <li class="htp-step"><div class="htp-num">5</div><div class="htp-text">❤️ You have 3 lives. Survive as long as possible for a top score!</div></li>\n      </ol>\n      <div class="htp-tip">💡 <span>Pro tip:</span> Keep your eyes centered so you can spot any zone instantly!</div>\n    </div>\n    <div class="htp-footer">\n      <button class="htp-go" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">GOT IT — LET\'S PLAY!</button>\n    </div>\n  </div>\n</div>\n<script>\n(function(){\n  var ov=document.getElementById(\'htp-modal\');\n  ov.addEventListener(\'click\',function(e){if(e.target===this)this.classList.remove(\'open\');});\n  document.addEventListener(\'keydown\',function(e){if(e.key===\'Escape\')ov.classList.remove(\'open\');});\n})();\n</script>\n\n</body>\n</html>'

ODD_ONE_OUT_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>MindBoost — Odd One Out</title>\n<link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@700;900&family=Rajdhani:wght@400;600&display=swap" rel="stylesheet">\n<style>\n  :root{--purple:#b537f2;--cyan:#00f5ff;--pink:#ff2d78;--green:#00e88a;--orange:#ff9f43;--bg:#050510;--card:rgba(15,10,40,0.85);--border:rgba(181,55,242,0.3);--text:#e8e0ff;--muted:#7a6f9a;}\n  *{margin:0;padding:0;box-sizing:border-box;}\n  body{font-family:\'Rajdhani\',sans-serif;background:var(--bg);color:var(--text);min-height:100vh;}\n  body::before{content:\'\';position:fixed;inset:0;pointer-events:none;background-image:linear-gradient(rgba(181,55,242,0.05) 1px,transparent 1px),linear-gradient(90deg,rgba(181,55,242,0.05) 1px,transparent 1px);background-size:40px 40px;}\n  nav{display:flex;align-items:center;justify-content:space-between;padding:14px 28px;border-bottom:1px solid var(--border);background:rgba(5,5,16,0.95);backdrop-filter:blur(16px);}\n  .nav-logo{font-family:\'Orbitron\',monospace;font-size:16px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;}\n  .nav-btn{padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--text);font-family:\'Rajdhani\',sans-serif;font-size:13px;font-weight:600;border-radius:6px;cursor:pointer;transition:all 0.2s;text-decoration:none;display:inline-block;letter-spacing:1px;}\n  .nav-btn:hover{background:rgba(181,55,242,0.2);border-color:var(--purple);color:var(--cyan);}\n  .container{max-width:640px;margin:0 auto;padding:24px 20px;position:relative;z-index:1;}\n\n  .hud{display:flex;justify-content:space-between;align-items:center;background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:12px;padding:14px 22px;margin-bottom:16px;}\n  .hud-item{text-align:center;}\n  .hud-label{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);}\n  .hud-value{font-family:\'Orbitron\',monospace;font-size:26px;font-weight:900;color:var(--cyan);}\n  .hud-value.warn{color:var(--orange);}\n  .hud-value.danger{color:var(--pink);animation:blink 0.5s infinite;}\n  @keyframes blink{0%,100%{opacity:1}50%{opacity:0.4}}\n\n  /* progress bar */\n  .progress-wrap{margin-bottom:14px;}\n  .progress-track{height:4px;background:rgba(255,255,255,0.06);border-radius:2px;overflow:hidden;}\n  .progress-fill{height:100%;background:linear-gradient(90deg,var(--purple),var(--cyan));border-radius:2px;transition:width 0.3s ease;}\n  .progress-labels{display:flex;justify-content:space-between;margin-top:6px;}\n  .prog-label{font-family:\'Orbitron\',monospace;font-size:10px;letter-spacing:2px;color:var(--muted);}\n\n  .board-wrap{background:rgba(15,10,40,0.85);border:1px solid var(--border);border-radius:16px;padding:24px;}\n\n  /* category hint */\n  .category-hint{text-align:center;margin-bottom:18px;}\n  .hint-label{font-size:11px;letter-spacing:3px;text-transform:uppercase;color:var(--muted);margin-bottom:6px;}\n  .hint-text{font-family:\'Orbitron\',monospace;font-size:15px;font-weight:700;color:var(--purple);letter-spacing:1px;}\n\n  /* options grid */\n  .options-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px;margin-bottom:16px;}\n  .option-btn{\n    padding:22px 16px;\n    background:rgba(255,255,255,0.04);\n    border:2px solid var(--border);\n    border-radius:14px;\n    display:flex;flex-direction:column;align-items:center;gap:10px;\n    cursor:pointer;transition:all 0.2s;\n    position:relative;overflow:hidden;\n  }\n  .option-btn::before{content:\'\';position:absolute;inset:0;opacity:0;transition:opacity 0.2s;background:linear-gradient(135deg,rgba(181,55,242,0.1),rgba(0,245,255,0.05));}\n  .option-btn:hover:not(.locked){border-color:rgba(181,55,242,0.5);transform:translateY(-3px);box-shadow:0 8px 20px rgba(181,55,242,0.15);}\n  .option-btn:hover:not(.locked)::before{opacity:1;}\n  .option-emoji{font-size:44px;line-height:1;}\n  .option-label{font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;letter-spacing:1px;color:var(--muted);text-align:center;}\n  .option-btn.locked{pointer-events:none;}\n\n  .option-btn.correct{\n    border-color:var(--green)!important;\n    background:rgba(0,232,138,0.1)!important;\n    animation:correctPop 0.4s ease;\n  }\n  .option-btn.correct .option-label{color:var(--green)!important;}\n  @keyframes correctPop{0%{transform:scale(0.95)}60%{transform:scale(1.05)}100%{transform:scale(1)}}\n\n  .option-btn.wrong{\n    border-color:var(--pink)!important;\n    background:rgba(255,45,120,0.08)!important;\n    animation:wrongShake 0.35s ease;\n  }\n  .option-btn.wrong .option-label{color:var(--pink)!important;}\n  @keyframes wrongShake{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}\n\n  /* reason reveal */\n  .reason-bar{\n    text-align:center;min-height:36px;padding:8px 16px;\n    border-radius:8px;margin-bottom:12px;\n    font-family:\'Orbitron\',monospace;font-size:11px;letter-spacing:1px;\n    transition:all 0.3s;opacity:0;\n  }\n  .reason-bar.show{opacity:1;}\n  .reason-bar.good{background:rgba(0,232,138,0.08);border:1px solid rgba(0,232,138,0.3);color:var(--green);}\n  .reason-bar.bad{background:rgba(255,45,120,0.08);border:1px solid rgba(255,45,120,0.3);color:var(--pink);}\n\n  /* streak indicator */\n  .streak-row{display:flex;align-items:center;justify-content:center;gap:6px;margin-bottom:14px;}\n  .streak-pip{width:10px;height:10px;border-radius:50%;border:1px solid var(--border);background:transparent;transition:all 0.2s;}\n  .streak-pip.hot{background:var(--orange);border-color:var(--orange);box-shadow:0 0 8px var(--orange);}\n  .streak-pip.done{background:var(--green);border-color:var(--green);}\n\n  .start-btn{display:block;width:100%;margin-top:4px;padding:13px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:10px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.25s;}\n  .start-btn:hover{box-shadow:0 6px 20px rgba(181,55,242,0.5);transform:translateY(-2px);}\n  .start-btn:disabled{opacity:0.4;cursor:default;transform:none;box-shadow:none;}\n\n  /* time-limit bar per question */\n  .time-bar-wrap{margin-bottom:14px;}\n  .time-bar-track{height:5px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;}\n  .time-bar-fill{height:100%;background:var(--cyan);border-radius:3px;transition:width 0.1s linear;}\n\n  .overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:200;align-items:center;justify-content:center;}\n  .overlay.show{display:flex;}\n  .result-card{background:rgba(15,10,40,0.98);border:1px solid var(--purple);border-radius:20px;padding:44px 40px;text-align:center;max-width:380px;width:90%;}\n  .result-card h2{font-family:\'Orbitron\',monospace;font-size:22px;color:var(--cyan);margin-bottom:8px;}\n  .result-score{font-family:\'Orbitron\',monospace;font-size:56px;font-weight:900;background:linear-gradient(135deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin:14px 0;}\n  .result-meta{color:var(--muted);font-size:14px;margin-bottom:4px;}\n  .result-stats{display:flex;gap:20px;justify-content:center;margin:16px 0;}\n  .r-stat-val{font-family:\'Orbitron\',monospace;font-size:22px;font-weight:900;color:var(--cyan);}\n  .r-stat-lbl{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);margin-top:2px;}\n  .result-btn{display:inline-block;padding:13px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:12px;}\n  .result-btn-sec{display:inline-block;padding:13px 28px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);font-family:\'Orbitron\',monospace;font-size:13px;font-weight:700;letter-spacing:2px;cursor:pointer;text-decoration:none;margin-top:8px;margin-left:8px;}\n  .result-btn-sec:hover{border-color:var(--cyan);color:var(--cyan);}\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── HOW TO PLAY MODAL ── */\n  .htp-btn{position:fixed;bottom:24px;right:24px;z-index:150;width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;color:white;font-size:20px;cursor:pointer;box-shadow:0 4px 20px rgba(181,55,242,0.5);transition:all 0.25s;display:flex;align-items:center;justify-content:center;}\n  .htp-btn:hover{transform:scale(1.12) translateY(-2px);box-shadow:0 8px 28px rgba(181,55,242,0.7);}\n  .htp-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.82);z-index:400;align-items:center;justify-content:center;backdrop-filter:blur(8px);padding:20px;}\n  .htp-overlay.open{display:flex;}\n  .htp-box{background:rgba(10,6,30,0.98);border:1px solid var(--border);border-radius:20px;max-width:480px;width:100%;overflow:hidden;animation:htpIn 0.25s ease;position:relative;}\n  @keyframes htpIn{from{opacity:0;transform:scale(0.94) translateY(-12px)}to{opacity:1;transform:none}}\n  .htp-header{padding:24px 28px 18px;border-bottom:1px solid var(--border);background:linear-gradient(135deg,rgba(181,55,242,0.12),rgba(0,245,255,0.06));position:relative;}\n  .htp-title{font-family:\'Orbitron\',monospace;font-size:17px;font-weight:900;background:linear-gradient(90deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;letter-spacing:2px;margin-bottom:4px;}\n  .htp-sub{font-size:12px;color:var(--muted);letter-spacing:1px;}\n  .htp-close{position:absolute;top:16px;right:18px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);width:32px;height:32px;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;}\n  .htp-close:hover{border-color:var(--pink);color:var(--pink);}\n  .htp-body{padding:24px 28px;}\n  .htp-steps{list-style:none;display:flex;flex-direction:column;gap:14px;}\n  .htp-step{display:flex;gap:14px;align-items:flex-start;}\n  .htp-num{flex-shrink:0;width:28px;height:28px;border-radius:8px;background:linear-gradient(135deg,rgba(181,55,242,0.3),rgba(0,245,255,0.15));border:1px solid rgba(181,55,242,0.4);display:flex;align-items:center;justify-content:center;font-family:\'Orbitron\',monospace;font-size:11px;font-weight:700;color:var(--cyan);}\n  .htp-text{font-size:14px;line-height:1.6;color:var(--text);padding-top:4px;}\n  .htp-text strong{color:var(--cyan);}\n  .htp-tip{margin-top:20px;padding:12px 16px;background:rgba(0,245,255,0.05);border:1px solid rgba(0,245,255,0.18);border-radius:10px;font-size:12px;color:var(--muted);line-height:1.6;}\n  .htp-tip span{color:var(--cyan);font-weight:700;}\n  .htp-footer{padding:16px 28px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;}\n  .htp-go{padding:11px 28px;background:linear-gradient(135deg,var(--purple),#6a0dad);border:none;border-radius:8px;color:white;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;letter-spacing:2px;cursor:pointer;transition:all 0.2s;}\n  .htp-go:hover{box-shadow:0 4px 16px rgba(181,55,242,0.5);transform:translateY(-1px);}\n\n\n  /* ── INSTRUCTIONS STRIP ── */\n  .instr-strip{background:rgba(15,10,40,0.85);border:1px solid rgba(0,245,255,0.2);border-radius:12px;padding:14px 20px;margin-bottom:20px;display:flex;gap:10px;flex-wrap:wrap;align-items:flex-start;}\n  .instr-strip-title{font-family:\'Orbitron\',monospace;font-size:10px;letter-spacing:2px;color:var(--cyan);text-transform:uppercase;margin-bottom:8px;display:block;}\n  .instr-steps{display:flex;flex-wrap:wrap;gap:8px;width:100%;}\n  .instr-step{display:flex;align-items:center;gap:6px;background:rgba(255,255,255,0.04);border:1px solid rgba(181,55,242,0.18);border-radius:8px;padding:6px 10px;font-size:12px;color:var(--text);line-height:1.4;}\n  .instr-step .i-num{font-family:\'Orbitron\',monospace;font-size:9px;font-weight:700;color:var(--cyan);background:rgba(0,245,255,0.1);border-radius:4px;padding:2px 5px;flex-shrink:0;}\n  .instr-step .i-icon{font-size:14px;flex-shrink:0;}\n  .instr-step strong{color:var(--cyan);}\n\n</style>\n</head>\n<body>\n<nav>\n  <div class="nav-logo">MINDBOOST</div>\n  <div style="display:flex;gap:8px;">\n    <a href="/dashboard" class="nav-btn">Dashboard</a>\n    <a href="/play" class="nav-btn">← Games</a>\n  </div>\n</nav>\n\n<div class="container">\n  <div class="hud">\n    <div class="hud-item"><div class="hud-label">Score</div>\n<!-- INSTR-INJECTED -->\n<div class="instr-strip">\n  <span class="instr-strip-title">📖 How to Play</span>\n  <div class="instr-steps">\n    <div class="instr-step"><span class="i-num">1</span><span class="i-icon">🔍</span>Four options appear — <strong>three share a trait</strong>, one does not</div>\n    <div class="instr-step"><span class="i-num">2</span><span class="i-icon">👆</span>Click the <strong>Odd One Out</strong> before the timer runs out</div>\n    <div class="instr-step"><span class="i-num">3</span><span class="i-icon">🔥</span>Correct answers build a <strong>streak bonus</strong> for extra points</div>\n    <div class="instr-step"><span class="i-num">4</span><span class="i-icon">🧠</span>Categories: colors, numbers, animals, words and more — <strong>think fast!</strong></div>\n  </div>\n</div><div class="hud-value" id="score">0</div></div>\n    <div class="hud-item"><div class="hud-label">🔍 Odd One Out</div><div style="color:var(--muted);font-size:12px;margin-top:4px;">Find what doesn\'t belong!</div></div>\n    <div class="hud-item"><div class="hud-label">Streak</div><div class="hud-value" id="streak">0</div></div>\n    <div class="hud-item"><div class="hud-label">Time</div><div class="hud-value" id="timer">60</div></div>\n  </div>\n\n  <div class="progress-wrap">\n    <div class="progress-track"><div class="progress-fill" id="progress-fill" style="width:0%"></div></div>\n    <div class="progress-labels">\n      <span class="prog-label">Q <span id="q-num">0</span></span>\n      <span class="prog-label"><span id="correct-count">0</span> CORRECT</span>\n    </div>\n  </div>\n\n  <div class="board-wrap">\n    <div class="category-hint">\n      <div class="hint-label">FIND THE ODD ONE OUT</div>\n      <div class="hint-text" id="hint-text">—</div>\n    </div>\n\n    <div class="time-bar-wrap">\n      <div class="time-bar-track"><div class="time-bar-fill" id="time-bar" style="width:100%"></div></div>\n    </div>\n\n    <div class="streak-row" id="streak-row"></div>\n\n    <div class="options-grid" id="options-grid"></div>\n\n    <div class="reason-bar" id="reason-bar"></div>\n\n    <button class="start-btn" id="start-btn" onclick="startGame()">▶ START GAME</button>\n  </div>\n</div>\n\n<div class="overlay" id="overlay">\n  <div class="result-card">\n    <h2>TIME\'S UP!</h2>\n    <div class="result-score" id="final-score">0</div>\n    <div class="result-meta">Final Score</div>\n    <div class="result-stats">\n      <div style="text-align:center"><div class="r-stat-val" id="final-q">0</div><div class="r-stat-lbl">Questions</div></div>\n      <div style="text-align:center"><div class="r-stat-val" id="final-acc">0%</div><div class="r-stat-lbl">Accuracy</div></div>\n      <div style="text-align:center"><div class="r-stat-val" id="final-streak">0</div><div class="r-stat-lbl">Best Streak</div></div>\n    </div>\n    <a href="/play" class="result-btn">BACK TO GAMES</a>\n    <button class="result-btn-sec" onclick="restartGame()">TRY AGAIN</button>\n  </div>\n</div>\n\n<script>\n// ── QUESTION BANK ─────────────────────────────────────────────────────────────\nconst QUESTIONS = [\n  // Animals\n  {hint:\'ANIMALS — which is NOT a mammal?\', items:[{e:\'🐶\',l:\'Dog\'},{e:\'🐱\',l:\'Cat\'},{e:\'🐸\',l:\'Frog\'},{e:\'🐭\',l:\'Mouse\'}], odd:2, reason:\'Frogs are amphibians, not mammals\'},\n  {hint:\'ANIMALS — which cannot fly?\', items:[{e:\'🦅\',l:\'Eagle\'},{e:\'🦆\',l:\'Duck\'},{e:\'🐧\',l:\'Penguin\'},{e:\'🦜\',l:\'Parrot\'}], odd:2, reason:\'Penguins cannot fly\'},\n  {hint:\'ANIMALS — which is a reptile?\', items:[{e:\'🐘\',l:\'Elephant\'},{e:\'🦁\',l:\'Lion\'},{e:\'🐊\',l:\'Crocodile\'},{e:\'🦒\',l:\'Giraffe\'}], odd:2, reason:\'Crocodiles are reptiles, others are mammals\'},\n  {hint:\'ANIMALS — which lives in water only?\', items:[{e:\'🐬\',l:\'Dolphin\'},{e:\'🐠\',l:\'Fish\'},{e:\'🦭\',l:\'Seal\'},{e:\'🐋\',l:\'Whale\'}], odd:1, reason:\'Fish must stay in water; others can surface\'},\n  {hint:\'ANIMALS — which has no legs?\', items:[{e:\'🐍\',l:\'Snake\'},{e:\'🦎\',l:\'Lizard\'},{e:\'🐢\',l:\'Turtle\'},{e:\'🦖\',l:\'Dinosaur\'}], odd:0, reason:\'Snakes have no legs\'},\n\n  // Food\n  {hint:\'FOOD — which is NOT a fruit?\', items:[{e:\'🍎\',l:\'Apple\'},{e:\'🥕\',l:\'Carrot\'},{e:\'🍇\',l:\'Grapes\'},{e:\'🍋\',l:\'Lemon\'}], odd:1, reason:\'Carrot is a vegetable\'},\n  {hint:\'FOOD — which has no seeds?\', items:[{e:\'🍓\',l:\'Strawberry\'},{e:\'🥚\',l:\'Egg\'},{e:\'🍉\',l:\'Watermelon\'},{e:\'🍊\',l:\'Orange\'}], odd:1, reason:\'Eggs are not a fruit and have no seeds\'},\n  {hint:\'FOOD — which is a dairy product?\', items:[{e:\'🥩\',l:\'Meat\'},{e:\'🧀\',l:\'Cheese\'},{e:\'🥦\',l:\'Broccoli\'},{e:\'🍞\',l:\'Bread\'}], odd:1, reason:\'Cheese is made from milk\'},\n  {hint:\'FOOD — which is NOT a vegetable?\', items:[{e:\'🌽\',l:\'Corn\'},{e:\'🥬\',l:\'Lettuce\'},{e:\'🍄\',l:\'Mushroom\'},{e:\'🥕\',l:\'Carrot\'}], odd:2, reason:\'Mushrooms are fungi, not vegetables\'},\n  {hint:\'FOOD — which can be drunk?\', items:[{e:\'🍕\',l:\'Pizza\'},{e:\'🧃\',l:\'Juice\'},{e:\'🍔\',l:\'Burger\'},{e:\'🌮\',l:\'Taco\'}], odd:1, reason:\'Juice is a beverage\'},\n\n  // Numbers & Math\n  {hint:\'NUMBERS — which is NOT prime?\', items:[{e:\'🔢\',l:\'7\'},{e:\'🔢\',l:\'11\'},{e:\'🔢\',l:\'9\'},{e:\'🔢\',l:\'13\'}], odd:2, reason:\'9 = 3×3, not a prime number\'},\n  {hint:\'NUMBERS — which is even?\', items:[{e:\'🔢\',l:\'7\'},{e:\'🔢\',l:\'13\'},{e:\'🔢\',l:\'8\'},{e:\'🔢\',l:\'19\'}], odd:2, reason:\'8 is the only even number\'},\n  {hint:\'NUMBERS — which is NOT a square number?\', items:[{e:\'🔢\',l:\'4\'},{e:\'🔢\',l:\'9\'},{e:\'🔢\',l:\'12\'},{e:\'🔢\',l:\'16\'}], odd:2, reason:\'12 is not a perfect square\'},\n\n  // Science\n  {hint:\'PLANETS — which is NOT in our solar system?\', items:[{e:\'🪐\',l:\'Saturn\'},{e:\'🌍\',l:\'Earth\'},{e:\'⭐\',l:\'Kepler\'},{e:\'🔴\',l:\'Mars\'}], odd:2, reason:\'Kepler-22b is outside our solar system\'},\n  {hint:\'SCIENCE — which is NOT a gas at room temp?\', items:[{e:\'💨\',l:\'Oxygen\'},{e:\'💨\',l:\'Nitrogen\'},{e:\'🧊\',l:\'Iron\'},{e:\'💨\',l:\'Helium\'}], odd:2, reason:\'Iron is a solid metal at room temperature\'},\n  {hint:\'ELEMENTS — which is NOT a metal?\', items:[{e:\'🔩\',l:\'Iron\'},{e:\'🔩\',l:\'Copper\'},{e:\'💎\',l:\'Carbon\'},{e:\'🔩\',l:\'Gold\'}], odd:2, reason:\'Carbon is a non-metal element\'},\n\n  // Countries & Geography\n  {hint:\'GEOGRAPHY — which is NOT in Europe?\', items:[{e:\'🇫🇷\',l:\'France\'},{e:\'🇩🇪\',l:\'Germany\'},{e:\'🇯🇵\',l:\'Japan\'},{e:\'🇮🇹\',l:\'Italy\'}], odd:2, reason:\'Japan is in Asia\'},\n  {hint:\'GEOGRAPHY — which is an island country?\', items:[{e:\'🌏\',l:\'China\'},{e:\'🌏\',l:\'Russia\'},{e:\'🌏\',l:\'Japan\'},{e:\'🌏\',l:\'India\'}], odd:2, reason:\'Japan is an island nation\'},\n  {hint:\'GEOGRAPHY — which is NOT a continent?\', items:[{e:\'🌍\',l:\'Africa\'},{e:\'🌏\',l:\'Asia\'},{e:\'🌊\',l:\'Pacific\'},{e:\'🌎\',l:\'Americas\'}], odd:2, reason:\'The Pacific is an ocean, not a continent\'},\n\n  // Sports\n  {hint:\'SPORTS — which uses a net?\', items:[{e:\'⚽\',l:\'Football\'},{e:\'🏀\',l:\'Basketball\'},{e:\'🏊\',l:\'Swimming\'},{e:\'🏋️\',l:\'Weightlifting\'}], odd:2, reason:\'Swimming does not use a net or ball\'},\n  {hint:\'SPORTS — which is an individual sport?\', items:[{e:\'⚽\',l:\'Football\'},{e:\'🏀\',l:\'Basketball\'},{e:\'🏊\',l:\'Swimming\'},{e:\'🏉\',l:\'Rugby\'}], odd:2, reason:\'Swimming is primarily an individual sport\'},\n\n  // Colors / Shapes\n  {hint:\'SHAPES — which has curved sides?\', items:[{e:\'🔷\',l:\'Diamond\'},{e:\'⬛\',l:\'Square\'},{e:\'🔺\',l:\'Triangle\'},{e:\'⭕\',l:\'Circle\'}], odd:3, reason:\'Only a circle has fully curved sides\'},\n  {hint:\'COLORS — which is NOT a primary color?\', items:[{e:\'🔵\',l:\'Blue\'},{e:\'🔴\',l:\'Red\'},{e:\'🟢\',l:\'Green\'},{e:\'🟡\',l:\'Yellow\'}], odd:2, reason:\'Green is not a primary color in traditional mixing\'},\n\n  // Music\n  {hint:\'MUSIC — which is a string instrument?\', items:[{e:\'🥁\',l:\'Drums\'},{e:\'🎺\',l:\'Trumpet\'},{e:\'🎸\',l:\'Guitar\'},{e:\'🪗\',l:\'Accordion\'}], odd:2, reason:\'Guitar is the only string instrument here\'},\n  {hint:\'MUSIC — which is NOT a wind instrument?\', items:[{e:\'🎺\',l:\'Trumpet\'},{e:\'🎷\',l:\'Saxophone\'},{e:\'🥁\',l:\'Drums\'},{e:\'🪗\',l:\'Flute (pictured)\'}], odd:2, reason:\'Drums are percussion, not wind\'},\n];\n\nlet score        = 0;\nlet streak       = 0;\nlet bestStreak   = 0;\nlet timeLeft     = 60;\nlet active       = false;\nlet timerRef     = null;\nlet qNum         = 0;\nlet correctCount = 0;\nlet attempts     = 0;\nlet qTimeRef     = null;\nlet qTimeLeft    = 0;\nconst Q_TIME     = 8000; // 8s per question\nconst STREAK_SHOW = 5;\n\nlet shuffledQ    = [];\nlet qIndex       = 0;\n\nfunction shuffle(arr) {\n  const a = [...arr];\n  for (let i = a.length - 1; i > 0; i--) {\n    const j = Math.floor(Math.random() * (i + 1));\n    [a[i], a[j]] = [a[j], a[i]];\n  }\n  return a;\n}\n\nfunction buildStreakPips() {\n  const row = document.getElementById(\'streak-row\');\n  row.innerHTML = \'\';\n  for (let i = 0; i < STREAK_SHOW; i++) {\n    const d = document.createElement(\'div\');\n    d.className = \'streak-pip\' + (i < streak ? (streak >= STREAK_SHOW ? \' hot\' : \' done\') : \'\');\n    row.appendChild(d);\n  }\n}\n\nfunction loadQuestion() {\n  if (!active) return;\n  clearTimeout(qTimeRef);\n\n  const q = shuffledQ[qIndex % shuffledQ.length];\n  qIndex++;\n  qNum++;\n\n  document.getElementById(\'q-num\').textContent      = qNum;\n  document.getElementById(\'hint-text\').textContent  = q.hint;\n\n  const grid = document.getElementById(\'options-grid\');\n  grid.innerHTML = \'\';\n\n  // shuffle option order but track which index is odd\n  const indices = shuffle([0,1,2,3]);\n  const newOddIdx = indices.indexOf(q.odd);\n\n  indices.forEach((origIdx, displayPos) => {\n    const item = q.items[origIdx];\n    const btn  = document.createElement(\'div\');\n    btn.className   = \'option-btn\';\n    btn.dataset.pos = displayPos;\n    btn.dataset.isOdd = (origIdx === q.odd) ? \'1\' : \'0\';\n    btn.innerHTML = `<span class="option-emoji">${item.e}</span><span class="option-label">${item.l}</span>`;\n    btn.onclick = () => handleAnswer(btn, q, origIdx === q.odd);\n    grid.appendChild(btn);\n  });\n\n  // hide reason\n  const rb = document.getElementById(\'reason-bar\');\n  rb.className = \'reason-bar\';\n  rb.textContent = \'\';\n\n  buildStreakPips();\n  updateProgress();\n  startQTimer();\n}\n\nfunction startQTimer() {\n  qTimeLeft = Q_TIME;\n  const bar = document.getElementById(\'time-bar\');\n  bar.style.transition = \'none\';\n  bar.style.width = \'100%\';\n  bar.style.background = \'var(--cyan)\';\n\n  const step = 50;\n  qTimeRef = setInterval(() => {\n    qTimeLeft -= step;\n    const pct = Math.max(0, (qTimeLeft / Q_TIME) * 100);\n    bar.style.transition = \'width 0.05s linear\';\n    bar.style.width = pct + \'%\';\n    if (pct < 30) bar.style.background = \'var(--orange)\';\n    if (pct < 10) bar.style.background = \'var(--pink)\';\n    if (qTimeLeft <= 0) {\n      clearInterval(qTimeRef);\n      timeoutQuestion();\n    }\n  }, step);\n}\n\nfunction timeoutQuestion() {\n  attempts++;\n  streak = 0;\n  document.getElementById(\'streak\').textContent = streak;\n  buildStreakPips();\n\n  // reveal correct answer\n  document.querySelectorAll(\'.option-btn\').forEach(btn => {\n    btn.classList.add(\'locked\');\n    if (btn.dataset.isOdd === \'1\') btn.classList.add(\'correct\');\n  });\n\n  showReason(\'⏱ TIME OUT — no points awarded\', \'bad\');\n  setTimeout(() => { if (active) loadQuestion(); }, 1100);\n}\n\nfunction handleAnswer(btn, q, isOdd) {\n  if (!active) return;\n  clearInterval(qTimeRef);\n  attempts++;\n\n  document.querySelectorAll(\'.option-btn\').forEach(b => b.classList.add(\'locked\'));\n\n  if (isOdd) {\n    // correct!\n    btn.classList.add(\'correct\');\n    streak++;\n    correctCount++;\n    if (streak > bestStreak) bestStreak = streak;\n    document.getElementById(\'streak\').textContent = streak;\n\n    const timeBonus = Math.round((qTimeLeft / Q_TIME) * 30);\n    const streakBonus = streak > 2 ? (streak - 2) * 5 : 0;\n    const pts = 50 + timeBonus + streakBonus;\n    score += pts;\n    document.getElementById(\'score\').textContent = score;\n    document.getElementById(\'correct-count\').textContent = correctCount;\n\n    const msg = streak >= 3 ? `🔥 ${streak}x STREAK! +${pts}` : `✓ CORRECT! +${pts}`;\n    showReason(msg + \'  ·  \' + q.reason, \'good\');\n  } else {\n    // wrong\n    btn.classList.add(\'wrong\');\n    streak = 0;\n    document.getElementById(\'streak\').textContent = streak;\n    // highlight correct\n    document.querySelectorAll(\'.option-btn\').forEach(b => {\n      if (b.dataset.isOdd === \'1\') b.classList.add(\'correct\');\n    });\n    showReason(\'✗ WRONG  ·  \' + q.reason, \'bad\');\n  }\n\n  buildStreakPips();\n  updateProgress();\n  setTimeout(() => { if (active) loadQuestion(); }, 1200);\n}\n\nfunction showReason(text, type) {\n  const rb = document.getElementById(\'reason-bar\');\n  rb.textContent = text;\n  rb.className   = `reason-bar show ${type}`;\n}\n\nfunction updateProgress() {\n  const pct = Math.min(100, (correctCount / 20) * 100);\n  document.getElementById(\'progress-fill\').style.width = pct + \'%\';\n}\n\nfunction startGame() {\n  if (active) return;\n  active       = true;\n  score        = 0;\n  streak       = 0;\n  bestStreak   = 0;\n  timeLeft     = 60;\n  qNum         = 0;\n  correctCount = 0;\n  attempts     = 0;\n  qIndex       = 0;\n  shuffledQ    = shuffle(QUESTIONS);\n\n  document.getElementById(\'score\').textContent         = 0;\n  document.getElementById(\'streak\').textContent        = 0;\n  document.getElementById(\'q-num\').textContent         = 0;\n  document.getElementById(\'correct-count\').textContent = 0;\n  document.getElementById(\'progress-fill\').style.width = \'0%\';\n  document.getElementById(\'start-btn\').disabled        = true;\n  document.getElementById(\'reason-bar\').className      = \'reason-bar\';\n\n  timerRef = setInterval(() => {\n    if (!active) { clearInterval(timerRef); return; }\n    timeLeft--;\n    const el = document.getElementById(\'timer\');\n    el.textContent = timeLeft;\n    el.className = \'hud-value\' + (timeLeft <= 10 ? \' danger\' : timeLeft <= 20 ? \' warn\' : \'\');\n    if (timeLeft === 0) endGame();\n  }, 1000);\n\n  loadQuestion();\n}\n\nfunction endGame() {\n  active = false;\n  clearInterval(timerRef);\n  clearInterval(qTimeRef);\n  document.querySelectorAll(\'.option-btn\').forEach(b => b.classList.add(\'locked\'));\n\n  const acc = attempts > 0 ? Math.round(correctCount / attempts * 100) : 0;\n  document.getElementById(\'final-score\').textContent  = score;\n  document.getElementById(\'final-q\').textContent      = qNum;\n  document.getElementById(\'final-acc\').textContent    = acc + \'%\';\n  document.getElementById(\'final-streak\').textContent = bestStreak;\n  document.getElementById(\'overlay\').classList.add(\'show\');\n\n  fetch(\'/save_score\', {\n    method: \'POST\',\n    headers: {\'Content-Type\':\'application/json\'},\n    body: JSON.stringify({game_name:\'Odd One Out\', score, time_taken: 60 - timeLeft, accuracy: acc})\n  });\n}\n\nfunction restartGame() {\n  document.getElementById(\'overlay\').classList.remove(\'show\');\n  document.getElementById(\'start-btn\').disabled   = false;\n  document.getElementById(\'timer\').className      = \'hud-value\';\n  document.getElementById(\'timer\').textContent    = 60;\n  document.getElementById(\'hint-text\').textContent = \'—\';\n  document.getElementById(\'options-grid\').innerHTML = \'\';\n  document.getElementById(\'streak-row\').innerHTML  = \'\';\n  document.getElementById(\'time-bar\').style.width  = \'100%\';\n  document.getElementById(\'time-bar\').style.background = \'var(--cyan)\';\n  startGame();\n}\n</script>\n\n<!-- HTP-INJECTED -->\n<!-- HOW TO PLAY BUTTON -->\n<button class="htp-btn" onclick="document.getElementById(\'htp-modal\').classList.add(\'open\')" title="How to Play">❓</button>\n\n<!-- HOW TO PLAY MODAL -->\n<div class="htp-overlay" id="htp-modal">\n  <div class="htp-box">\n    <div class="htp-header">\n      <div class="htp-title">ODD ONE OUT</div>\n      <div class="htp-sub">Find the item that doesn\'t belong</div>\n      <button class="htp-close" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">✕</button>\n    </div>\n    <div class="htp-body">\n      <ol class="htp-steps">\n        <li class="htp-step"><div class="htp-num">1</div><div class="htp-text">🔍 Four options appear — three share something in common, <strong>one does not</strong>.</div></li>\n        <li class="htp-step"><div class="htp-num">2</div><div class="htp-text">👆 Identify the <strong>odd one out</strong> and click it before time runs out.</div></li>\n        <li class="htp-step"><div class="htp-num">3</div><div class="htp-text">🔥 Correct answers build a <strong>streak bonus</strong> for extra points.</div></li>\n        <li class="htp-step"><div class="htp-num">4</div><div class="htp-text">⚠️ A wrong pick or timing out <strong>breaks your streak</strong> and advances to the next question.</div></li>\n        <li class="htp-step"><div class="htp-num">5</div><div class="htp-text">🧠 Categories include colors, numbers, animals, words and more — <strong>think fast!</strong></div></li>\n      </ol>\n      <div class="htp-tip">💡 <span>Pro tip:</span> Look for the most obvious connection first — size, color, category, or spelling!</div>\n    </div>\n    <div class="htp-footer">\n      <button class="htp-go" onclick="document.getElementById(\'htp-modal\').classList.remove(\'open\')">GOT IT — LET\'S PLAY!</button>\n    </div>\n  </div>\n</div>\n<script>\n(function(){\n  var ov=document.getElementById(\'htp-modal\');\n  ov.addEventListener(\'click\',function(e){if(e.target===this)this.classList.remove(\'open\');});\n  document.addEventListener(\'keydown\',function(e){if(e.key===\'Escape\')ov.classList.remove(\'open\');});\n})();\n</script>\n\n</body>\n</html>'



# ── HELPERS ───────────────────────────────────────────────────────────────────
def calculate_brain_level(total_score):
    for level, threshold in enumerate([100, 300, 600, 1000, 1500, 2200, 3000, 4000, 5500], 1):
        if total_score < threshold:
            return level
    return 10


def get_user(username):
    try:
        return users_table.get_item(Key={"username": username}).get("Item")
    except ClientError as e:
        print(f"[DynamoDB ERROR] get_user: {e}")
        return None


def get_user_history(username, limit=20):
    try:
        return history_table.query(
            KeyConditionExpression=boto3.dynamodb.conditions.Key("username").eq(username),
            ScanIndexForward=False,
            Limit=limit
        ).get("Items", [])
    except ClientError as e:
        print(f"[DynamoDB ERROR] get_user_history: {e}")
        return []


def update_daily_streak(user):
    today = datetime.now().date()
    last  = user.get("last_played_date")
    if last:
        delta = (today - datetime.strptime(last, "%Y-%m-%d").date()).days
        if delta == 1:
            user["daily_streak"] = int(user.get("daily_streak", 0)) + 1
        elif delta > 1:
            user["daily_streak"] = 1
    else:
        user["daily_streak"] = 1
    user["last_played_date"] = today.strftime("%Y-%m-%d")
    return user


def publish_sns_alert(username, game_name, score):
    if score < 40:
        msg, level = "Keep practicing - improvement comes with consistency", "low"
    elif score <= 70:
        msg, level = "Good work - you are making progress", "mid"
    else:
        msg, level = "Amazing performance! Brain power rising", "high"
    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=f"MindBoost | {game_name} Result - Score: {score}",
            Message=(f"Hi {username},\n\nGame: {game_name}\nScore: {score}\n"
                     f"Result: {msg}\nDate: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n\n"
                     f"Keep training!\n- MindBoost Arena Pro")
        )
        print(f"[SNS] {username} | {game_name} | {score}")
        return True, level, msg
    except ClientError as e:
        print(f"[SNS ERROR] {e}")
        return False, level, msg


def subscribe_email(email):
    try:
        sns_client.subscribe(TopicArn=SNS_TOPIC_ARN, Protocol="email",
                             Endpoint=email, ReturnSubscriptionArn=True)
        print(f"[SNS SUBSCRIBE] {email}")
        return True
    except ClientError as e:
        print(f"[SNS SUBSCRIBE ERROR] {e}")
        return False


def unsubscribe_email(sub_arn):
    if not sub_arn or sub_arn == "PendingConfirmation":
        return
    try:
        sns_client.unsubscribe(SubscriptionArn=sub_arn)
        print(f"[SNS UNSUBSCRIBE] {sub_arn}")
    except ClientError as e:
        print(f"[SNS UNSUBSCRIBE ERROR] {e}")


# ── AUTH ──────────────────────────────────────────────────────────────────────
@app.route("/")
def index():
    if "username" in session:
        return redirect(url_for("dashboard"))
    return redirect(url_for("login"))


@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "POST":
        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")
        user = get_user(username)
        if user and user.get("password") == password:
            session["username"] = username
            print(f"[LOGIN] {username}")
            return redirect(url_for("dashboard"))
        flash("Invalid username or password", "danger")
    return render_template("login.html")


@app.route("/register", methods=["GET", "POST"])
def register():
    if request.method == "POST":
        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")

        if not username or not password:
            flash("Username and password are required", "danger")
            return render_template("register.html")

        if get_user(username):
            flash("Username already exists", "danger")
            return render_template("register.html")

        try:
            users_table.put_item(Item={
                "username":             username,
                "password":             password,
                "total_score":          0,
                "brain_level":          1,
                "daily_streak":         0,
                "last_played_date":     None,
                "email":                None,
                "game_alerts":          False,
                "highscore_alerts":     False,
                "streak_alerts":        False,
                "sns_subscription_arn": None,
                "notifications":        []
            })
            print(f"[REGISTER] {username}")
            flash("Account created! Please sign in.", "success")
            return redirect(url_for("login"))
        except ClientError as e:
            flash(f"Registration failed: {e.response['Error']['Message']}", "danger")
            return render_template("register.html")

    return render_template("register.html")


@app.route("/logout")
def logout():
    username = session.pop("username", None)
    print(f"[LOGOUT] {username}")
    return redirect(url_for("login"))


