@app.route("/alerts", methods=["GET", "POST"])
def alerts():
    if "username" not in session:
        return redirect(url_for("login"))
    username = session["username"]
    user = get_user(username)

    if request.method == "POST":
        action = request.form.get("action")
        email_list = list(user.get("notification_emails") or [])

        if action == "save_email":
            email = request.form.get("email", "").strip().lower()
            if not email:
                flash("Please enter a valid email address.", "danger")
            elif any(e["email"] == email for e in email_list):
                flash(f"{email} is already subscribed.", "info")
            else:
                subscribe_email(email)
                email_list.append({
                    "email":    email,
                    "status":   "pending",
                    "added_at": datetime.now().strftime("%Y-%m-%dT%H:%M:%S")
                })
                users_table.update_item(
                    Key={"username": username},
                    UpdateExpression="SET notification_emails = :e",
                    ExpressionAttributeValues={":e": email_list}
                )
                flash(f"Subscribed! Check {email} for a confirmation link.", "success")

        elif action == "remove_email":
            email = request.form.get("email", "").strip().lower()
            entry = next((e for e in email_list if e["email"] == email), None)
            if entry:
                unsubscribe_email(entry.get("sns_arn"))
                email_list = [e for e in email_list if e["email"] != email]
                users_table.update_item(
                    Key={"username": username},
                    UpdateExpression="SET notification_emails = :e",
                    ExpressionAttributeValues={":e": email_list}
                )
                flash(f"{email} removed from alerts.", "success")
            else:
                flash("Email not found.", "danger")

        user = get_user(username)

    notification_emails = user.get("notification_emails") or []
    return render_template("alerts.html", user=user, username=username,
                           notification_emails=notification_emails)


# ── SAVE SCORE ────────────────────────────────────────────────────────────────
@app.route("/save_score", methods=["POST"])
def save_score():
    if "username" not in session:
        return jsonify({"success": False}), 401

    username   = session["username"]
    data       = request.json
    game_name  = data.get("game_name", "Unknown")
    score      = int(data.get("score", 0))
    time_taken = int(data.get("time_taken", 0))
    accuracy   = int(data.get("accuracy", 0))

    user = get_user(username)
    if not user:
        return jsonify({"success": False}), 404

    # 1 — Save to mindboost_game_history
    try:
        history_table.put_item(Item={
            "username":  username,
            "played_at": datetime.now().strftime("%Y-%m-%dT%H:%M:%S"),
            "game_id":   str(uuid.uuid4()),
            "game":      game_name,
            "score":     score,
            "time":      time_taken,
            "accuracy":  accuracy,
            "date":      datetime.now().strftime("%Y-%m-%d %H:%M")
        })
    except ClientError as e:
        print(f"[DynamoDB ERROR] history: {e}")

    # 2 — Update streak and totals in mindboost-users
    user      = update_daily_streak(dict(user))
    new_total = int(user.get("total_score", 0)) + score
    new_level = calculate_brain_level(new_total)
    try:
        users_table.update_item(
            Key={"username": username},
            UpdateExpression="SET total_score = :ts, brain_level = :bl, "
                             "daily_streak = :ds, last_played_date = :ld",
            ExpressionAttributeValues={
                ":ts": new_total, ":bl": new_level,
                ":ds": int(user["daily_streak"]), ":ld": user["last_played_date"]
            }
        )
    except ClientError as e:
        print(f"[DynamoDB ERROR] update user: {e}")

    print(f"[SCORE SAVED] {username} | {game_name} | {score}")

    # 3 — SNS game result alert
    if user.get("email") and user.get("game_alerts"):
        ok, level, perf_msg = publish_sns_alert(username, game_name, score)
        try:
            users_table.update_item(
                Key={"username": username},
                UpdateExpression="SET notifications = list_append("
                                 "if_not_exists(notifications, :e), :n)",
                ExpressionAttributeValues={
                    ":n": [{"game": game_name, "score": score, "message": perf_msg,
                            "level": level, "date": datetime.now().strftime("%Y-%m-%d %H:%M")}],
                    ":e": []
                }
            )
        except ClientError as e:
            print(f"[DynamoDB ERROR] notifications: {e}")

    # 4 — SNS high score alert
    if user.get("email") and user.get("highscore_alerts") and score > 80:
        try:
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Subject=f"New High Score in {game_name}!",
                Message=(f"Hi {username},\n\nYou scored {score} in {game_name} "
                         f"- outstanding!\n\n- MindBoost Arena Pro")
            )
        except ClientError as e:
            print(f"[SNS HIGH SCORE ERROR] {e}")

    return jsonify({"success": True, "brain_level": new_level, "total_score": new_total})


